            </Space>
          </Col>
        </Row>
      </Card>

      {/* 表格 */}
      <Card bordered={false}>
        <Table
          dataSource={data?.items || []}
          columns={columns}
          rowKey="id"
          size="middle"
          loading={loading}
          scroll={{ x: 900 }}
          pagination={{
            current: data?.page || 1,
            pageSize: data?.pageSize || 10,
            total: data?.total || 0,
            showSizeChanger: true,
            showQuickJumper: true,
            showTotal: (total) => `共 ${total} 条记录`,
            onChange: handlePageChange,
          }}
        />
      </Card>

      {/* 详情抽屉 */}
      <AnalysisDetailDrawer
        open={detailOpen}
        loading={detailLoading}
        data={detailData}
        onClose={() => {
          setDetailOpen(false);
          setDetailData(null);
          setSelectedRecordId(null);
        }}
      />
    </div>
  );
}

