              <Text type="secondary" style={{ display: 'block', fontSize: 11 }}>
                <MailOutlined style={{ marginRight: 3 }} />
                {record.email}
              </Text>
            )}
          </div>
        </Space>
      ),
    },
    {
      title: 'GitHub 统计',
      key: 'github_stats',
