      {/* 统计卡片 */}
      <Row gutter={16} style={{ marginBottom: 24 }}>
        <Col xs={12} lg={6}>
          <Card bordered={false} size="small">
            <Text type="secondary">总用户数</Text>
            <div style={{ fontSize: 24, fontWeight: 600, color: '#1677ff' }}>
              {users?.total || 0}
            </div>
          </Card>
        </Col>
        <Col xs={12} lg={6}>
          <Card bordered={false} size="small">
            <Text type="secondary">活跃用户</Text>
