              {users?.items.filter((u) => u.email).length || 0}
            </div>
          </Card>
        </Col>
        <Col xs={12} lg={6}>
          <Card bordered={false} size="small">
            <Text type="secondary">总仓库数</Text>
            <div style={{ fontSize: 24, fontWeight: 600, color: '#fa8c16' }}>
              {users?.items.reduce((acc, u) => acc + u.public_repos, 0) || 0}
