                    showTotal: (total) => `共 ${total} 条记录`,
                    onChange: handleHistoryPageChange,
                  }}
                />
              </div>
            </>
          )}
        </Spin>
      </Drawer>

      {/* 详情抽屉 */}
      <AnalysisDetailDrawer
        open={detailOpen}
        loading={detailLoading}
        data={detailData}
        onClose={() => {
          setDetailOpen(false);
          setDetailData(null);
        }}
      />
    </div>
  );
}

